import{_ as l,r as o,o as s,c as d,e as c,a as r,b as t,d as n,w as h}from"./app-cb4a12e2.js";const g={},u={href:"https://js.langchain.com/docs/",target:"_blank",rel:"noopener noreferrer"},p={href:"https://sdk.vercel.ai/docs",target:"_blank",rel:"noopener noreferrer"},m={href:"https://echarts.apache.org/examples/en/index.html",target:"_blank",rel:"noopener noreferrer"};function b(f,e){const a=o("ExternalLinkIcon"),i=o("RouterLink");return s(),d("div",null,[e[4]||(e[4]=c('<h1 id="_03-project-构建智能数据分析核心" tabindex="-1"><a class="header-anchor" href="#_03-project-构建智能数据分析核心" aria-hidden="true">#</a> 03-project: 构建智能数据分析核心</h1><h1 id="_03-project-building-the-intelligent-agent-core" tabindex="-1"><a class="header-anchor" href="#_03-project-building-the-intelligent-agent-core" aria-hidden="true">#</a> 03-project: Building the Intelligent Agent Core</h1><h2 id="🎯-学习目标-learning-objectives" tabindex="-1"><a class="header-anchor" href="#🎯-学习目标-learning-objectives" aria-hidden="true">#</a> 🎯 学习目标 / Learning Objectives</h2><ol><li><strong>Agent 核心模块实现</strong>: 动手实现 NLU (意图识别)、Tool-use (工具调用)、Memory (记忆)、Reflection (反思)。</li><li><strong>构建 RAG 增强检索</strong>: 结合向量数据库 (pgvector) 实现知识库问答。</li><li><strong>数据可视化生成</strong>: 让 AI 自动生成 ECharts 配置并在前端渲染。</li><li><strong>端到端智能分析</strong>: 实现从“自然语言提问”到“图表展示”的完整闭环。</li></ol><h2 id="⏱️-预计时长-estimated-duration" tabindex="-1"><a class="header-anchor" href="#⏱️-预计时长-estimated-duration" aria-hidden="true">#</a> ⏱️ 预计时长 / Estimated Duration</h2><ul><li><strong>阅读</strong>: 3 小时 / 3 Hours</li><li><strong>实验</strong>: 4-8 小时 / 4-8 Hours</li></ul><h2 id="📦-交付物清单-deliverables-checklist" tabindex="-1"><a class="header-anchor" href="#📦-交付物清单-deliverables-checklist" aria-hidden="true">#</a> 📦 交付物清单 / Deliverables Checklist</h2><ul><li>[ ] 一个具备“思考”能力的 AI Agent 后端服务</li><li>[ ] 支持 SQL 查询与图表生成的工具集 (Tools)</li><li>[ ] 前端流式对话界面 (Streaming Chat UI)</li><li>[ ] 能够根据指令自动渲染 ECharts 图表的组件</li></ul><h2 id="🧠-核心概念-core-concepts" tabindex="-1"><a class="header-anchor" href="#🧠-核心概念-core-concepts" aria-hidden="true">#</a> 🧠 核心概念 / Core Concepts</h2><h3 id="_1-react-模式-reasoning-acting" tabindex="-1"><a class="header-anchor" href="#_1-react-模式-reasoning-acting" aria-hidden="true">#</a> 1. ReAct 模式 (Reasoning + Acting)</h3><p>Agent 的核心循环：</p><ol><li><strong>Thought</strong>: 思考用户意图，拆解任务。</li><li><strong>Action</strong>: 选择并调用工具 (API, SQL, Search)。</li><li><strong>Observation</strong>: 观察工具返回的结果。</li><li><strong>Reflection</strong>: 反思结果是否满足需求，决定下一步行动或输出最终答案。</li></ol><h3 id="_2-工具调用-function-calling-tool-use" tabindex="-1"><a class="header-anchor" href="#_2-工具调用-function-calling-tool-use" aria-hidden="true">#</a> 2. 工具调用 (Function Calling / Tool Use)</h3><p>LLM 不直接操作数据库，而是通过定义清晰的工具接口 (JSON Schema) 来与外部世界交互。</p><ul><li><code>query_database(sql: string)</code>: 执行 SQL 查询。</li><li><code>generate_chart(config: json)</code>: 生成图表配置。</li></ul><h3 id="_3-结构化输出-structured-output" tabindex="-1"><a class="header-anchor" href="#_3-结构化输出-structured-output" aria-hidden="true">#</a> 3. 结构化输出 (Structured Output)</h3><p>强制 LLM 输出 JSON 格式，以便程序解析。例如，前端需要的 ECharts 配置必须是合法的 JSON 对象。</p><h3 id="_4-记忆管理-memory-management" tabindex="-1"><a class="header-anchor" href="#_4-记忆管理-memory-management" aria-hidden="true">#</a> 4. 记忆管理 (Memory Management)</h3><ul><li><strong>Short-term Memory</strong>: 当前对话上下文。</li><li><strong>Long-term Memory</strong>: 历史对话摘要，向量存储。</li></ul><h2 id="🛠️-实验步骤概览-lab-steps-overview" tabindex="-1"><a class="header-anchor" href="#🛠️-实验步骤概览-lab-steps-overview" aria-hidden="true">#</a> 🛠️ 实验步骤概览 / Lab Steps Overview</h2><ol><li><strong>Tool Definition</strong>: 定义 <code>QueryTool</code> 和 <code>ChartTool</code>。</li><li><strong>Agent Implementation</strong>: 使用 LangChain 或原生 API 实现 ReAct 循环。</li><li><strong>Frontend Integration</strong>: 使用 <code>ai/rsc</code> (Vercel AI SDK) 实现流式 UI。</li><li><strong>Visualization</strong>: 创建 <code>ChartRenderer</code> 组件，动态渲染 AI 生成的图表。</li></ol><h2 id="📚-推荐阅读-recommended-reading" tabindex="-1"><a class="header-anchor" href="#📚-推荐阅读-recommended-reading" aria-hidden="true">#</a> 📚 推荐阅读 / Recommended Reading</h2>',22)),r("ul",null,[r("li",null,[r("a",u,[e[0]||(e[0]=t("LangChain JS/TS Docs",-1)),n(a)])]),r("li",null,[r("a",p,[e[1]||(e[1]=t("Vercel AI SDK Core",-1)),n(a)])]),r("li",null,[r("a",m,[e[2]||(e[2]=t("ECharts Examples",-1)),n(a)])])]),e[5]||(e[5]=r("hr",null,null,-1)),r("p",null,[n(i,{to:"/blogs/2026/AI-Agent-Data-Analyzer/03-project/lab/"},{default:h(()=>[...e[3]||(e[3]=[t("Next Step: Start the Lab ->",-1)])]),_:1})])])}const x=l(g,[["render",b],["__file","index.html.vue"]]);export{x as default};
